body.script:
self.__next_f.push([1,"
html{background:#0000f2;overflow-x:clip}
body{background:#0000f2;color:#f5f5f5}
body main{background:#0000f2}
.hermes-web{
 background:#0000f2;
 color:#f5f5f5;
 min-height:100dvh;
 width:100dvw;
 margin-inline:calc(50% - 50dvw);
 container-type:inline-size;
 --u-anchor:0.58px;
 --u:max(calc(100cqw / 2360),var(--u-anchor));
 --vsq:calc(0.5vw + 0.5vh);
 --hw-gutter:calc(210 * var(--u));
 --hw-gap:calc(30 * var(--u));
 --hw-frame:calc(2.5 * var(--vsq));
 --hw-install-scroll-margin:calc(var(--hw-frame) + 180 * var(--u));
 --hw-text-eyebrow:calc(18 * var(--u));
 --hw-text-body:calc(21 * var(--u));
 font-family:var(--font-sigurd),'Times New Roman',serif;
 text-transform:uppercase;
 font-synthesis:none;
 -webkit-font-smoothing:antialiased;
}
.hermes-web svg{
 display:inline-block;
 vertical-align:middle;
 flex-shrink:0;
 max-width:2rem;
 max-height:2rem;
}
.hermes-web nav{
 position:absolute;
 inset-inline:0;
 top:var(--hw-frame);
 z-index:20;
 display:grid;
 grid-template-columns:1fr auto 1fr;
 align-items:start;
 padding-inline:var(--hw-gutter);
 padding-top:calc(50 * var(--u));
}
/* Layered so Tailwind utilities (layer `utilities`, e.g. the nav links'
 hover:underline) can override; unlayered rules would always win. Still
 guards the pre-stylesheet flash of UA-default underlines. */
@layer base{
 .hermes-web nav a,
 .hermes-web nav a:visited{
 color:inherit;
 text-decoration:none;
 }
}
.hw-scroll{
 position:relative;
 z-index:2;
 padding:var(--hw-frame) var(--hw-frame) 0;
 pointer-events:none;
}
.hw-scroll > :not([aria-hidden]){
 pointer-events:auto;
}
.hermes-web header.hw-vignette{
 position:relative;
 display:flex;
 min-height:calc(1360 * var(--u));
 overflow-x:clip;
}
.hermes-web header.hw-vignette > div{
 position:relative;
 z-index:3;
 margin-inline:var(--hw-gutter);
 max-width:100%;
 display:flex;
 flex-direction:column;
 gap:calc(30 * var(--u));
}
@media (min-width:768px){
 .hermes-web header.hw-vignette{
 align-items:flex-start;
 overflow:hidden;
 padding-top:calc(442 * var(--u));
 }
}
@media (max-width:767px){
 .hermes-web{
 --u:min(calc(100cqw / 760),var(--u-anchor));
 --hw-gutter:calc(48 * var(--u));
 --hw-install-scroll-margin:calc(var(--hw-frame) + 120 * var(--u));
 }
 .hermes-web header.hw-vignette{
 align-items:flex-end;
 min-height:88dvh;
 padding-top:calc(var(--hw-frame) + 210 * var(--u));
 padding-bottom:8dvh;
 }
}
"])
